-- Schéma cible PostgreSQL du service Catalog (UC7).
-- Équivalent LISIBLE de `dotnet ef migrations script` : en pratique, c'est EF Core qui GÉNÈRE ce
-- DDL à partir du DbContext. Ne pas maintenir ce fichier à la main en parallèle des migrations —
-- il sert de référence de lecture et pour la voie psql / MCP base de données.

CREATE TABLE "Categories" (
    "Id"   integer GENERATED BY DEFAULT AS IDENTITY,
    "Name" varchar(100) NOT NULL,
    CONSTRAINT "PK_Categories" PRIMARY KEY ("Id")
);

CREATE TABLE "Products" (
    "Id"             integer GENERATED BY DEFAULT AS IDENTITY,
    "Sku"            varchar(40)   NOT NULL,
    "Name"           varchar(200)  NOT NULL,
    "Description"    varchar(2000),
    "Price"          numeric(18,2) NOT NULL,
    "AvailableStock" integer       NOT NULL,
    "CategoryId"     integer       NOT NULL,
    CONSTRAINT "PK_Products" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_Products_Categories_CategoryId" FOREIGN KEY ("CategoryId")
        REFERENCES "Categories" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "ck_products_price_positive" CHECK ("Price" >= 0),
    CONSTRAINT "ck_products_stock_positive" CHECK ("AvailableStock" >= 0)
);

CREATE UNIQUE INDEX "IX_Categories_Name"     ON "Categories" ("Name");
CREATE UNIQUE INDEX "IX_Products_Sku"        ON "Products" ("Sku");
CREATE INDEX        "IX_Products_CategoryId" ON "Products" ("CategoryId");

-- ─────────────────────────────────────────────────────────────────────────────
-- Optimisation : lire le plan d'une requête fréquente (filtre par catégorie + tri prix).
-- EXPLAIN ANALYZE EXÉCUTE la requête (sûr ici, c'est un SELECT) et affiche le plan RÉEL.
-- L'index IX_Products_CategoryId évite un Seq Scan sur un gros catalogue.
EXPLAIN ANALYZE
SELECT "Id", "Name", "Price", "AvailableStock"
FROM   "Products"
WHERE  "CategoryId" = 1
ORDER  BY "Price";
